mapper.select:
SELECT id, post_id, user_id, content, images, parent_id, replied_user_id, deleted, like_count, created_at FROM ( SELECT id, post_id, user_id, content, images, parent_id, replied_user_id, deleted, like_count, created_at, ROW_NUMBER() OVER ( PARTITION BY post_id ORDER BY
COALESCE(like_count, 0) DESC, id DESC
COALESCE(created_at, FROM_UNIXTIME(0)) DESC, id DESC
) AS rn FROM t_feed_comment WHERE deleted = 0 AND post_id IN
#{pid}
) t WHERE t.rn <= #{limit} ORDER BY t.post_id, t.rn
